"""Recursos embebidos (logo BMI en base64) para que el .exe los lleve siempre dentro.

No depende de archivos de datos externos: al ser un módulo .py, Nuitka/PyInstaller lo
empaquetan automáticamente. Usa load_logo_pixmap()/make_logo_icon() desde la GUI.
"""
from __future__ import annotations

import base64

from PySide6.QtCore import Qt
from PySide6.QtGui import QPixmap, QIcon

_LOGO_256_B64 = ""

_LOGO_512_B64 = ""

_QR_B64 = ""


def load_qr_pixmap(size: int = 240) -> QPixmap:
    """QR de donación (Buy Me a Coffee) embebido, escalado a ``size``."""
    pix = QPixmap()
    pix.loadFromData(base64.b64decode(_QR_B64), "PNG")
    if not pix.isNull() and size:
        pix = pix.scaled(size, size, Qt.AspectRatioMode.KeepAspectRatio,
                         Qt.TransformationMode.SmoothTransformation)
    return pix


def load_logo_pixmap(size: int = 256) -> QPixmap:
    """Devuelve el logo BMI como QPixmap escalado a ``size`` (lado mayor)."""
    data = _LOGO_512_B64 if size > 256 else _LOGO_256_B64
    pix = QPixmap()
    pix.loadFromData(base64.b64decode(data), "PNG")
    if not pix.isNull() and size and size != pix.width():
        pix = pix.scaled(size, size, Qt.AspectRatioMode.KeepAspectRatio,
                         Qt.TransformationMode.SmoothTransformation)
    return pix


def make_logo_icon() -> QIcon:
    """Icono de la app a partir del logo (varios tamaños para nitidez)."""
    icon = QIcon()
    for s in (16, 32, 48, 64, 128, 256):
        icon.addPixmap(load_logo_pixmap(s if s <= 256 else 512))
    return icon
